diff --git a/llvm/lib/Transforms/Utils/LoopPeel.cpp b/llvm/lib/Transforms/Utils/LoopPeel.cpp
index 3cbde39b30b4..39df9764b758 100644
--- a/llvm/lib/Transforms/Utils/LoopPeel.cpp
+++ b/llvm/lib/Transforms/Utils/LoopPeel.cpp
@@ -1070,6 +1070,37 @@ bool llvm::peelLoop(Loop *L, unsigned PeelCount, LoopInfo *LI,
     PHI->setIncomingValueForBlock(NewPreHeader, NewVal);
   }

+  // Also adjust exit-block PHIs to take their value for the new preheader
+  // from the last peeled iteration's value mapped via LVMap. This ensures
+  // LCSSA PHIs and other exit PHIs reflect the correct value produced by the
+  // peeled iteration that precedes the remaining loop.
+  // Fix exit-block PHIs so that the incoming for the original in-loop
+  // predecessor (ExitFrom) reflects the value produced by the last peeled
+  // iteration when it exits. We already added an incoming for the cloned
+  // exiting block during peeling; reuse that value for the original ExitFrom.
+  for (auto &Edge : ExitEdges) {
+    BasicBlock *ExitFrom = Edge.first;   // Original exiting block inside the loop
+    BasicBlock *ExitTo = Edge.second;    // Exit block outside the loop
+
+    // LVMap maps original blocks to their last peeled copies.
+    auto It = LVMap.find(ExitFrom);
+    if (It == LVMap.end())
+      continue;
+    auto *ClonedExitFrom = dyn_cast_or_null<BasicBlock>(It->second);
+    if (!ClonedExitFrom)
+      continue;
+
+    for (PHINode &PHI : ExitTo->phis()) {
+      int PeeledIdx = PHI.getBasicBlockIndex(ClonedExitFrom);
+      int OrigIdx = PHI.getBasicBlockIndex(ExitFrom);
+      if (PeeledIdx < 0 || OrigIdx < 0)
+        continue;
+      Value *PeeledIncoming = PHI.getIncomingValue(PeeledIdx);
+      PHI.setIncomingValue(OrigIdx, PeeledIncoming);
+      SE->forgetLcssaPhiWithNewPredecessor(L, &PHI);
+    }
+  }
+
   for (const auto &[Term, Info] : Weights) {
     setBranchWeights(*Term, Info.Weights, /*IsExpected=*/false);
   }
